use std::fs;
use std::io;
use std::path::{Path, PathBuf};
use std::process::Command;
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};
use tokio;
use tokio::fs::File;
use tokio::prelude::*;
use tokio::sync::mpsc;
use tokio::time::sleep;
use tokio_util::sync::CancellationToken;

use notify::{Watcher, RecursiveMode};
use log::{error, info};

const BACKUP_DIR: &str = "backup";
const WATCH_DIR: &str = "watch_dir";

async fn run() {
    let args: Vec<String> = env::args().collect();

    if args.len() < 3 {
        eprintln!("Usage: {} WATCH_DIR BACKUP_DIR", args[0]);
        std::process::exit(1);
    }

    let watch_dir = &args[1];
    let backup_dir = &args[2];

    create_backup_dir(backup_dir).await;

    let mut watcher = Watcher::new(watch_dir, RecursiveMode::NonRecursive)
        .antivirus(false)
        .follow Symlink::FollowSymlink(false)
        .event_type([EventKind::Modified, EventKind::Created])
        .open_watchdog();

    let (tx, rx) = mpsc::channel(10);

    tokio::spawn(async move {
        for event in watcher {
            if let Ok(event) = event {
                tx.send(event).unwrap();
            }
        }
    });

    tokio::spawn(async move {
        let mut file_tx = File::create(backup_dir / "file_timestamps").unwrap();
        file_tx.write_all(b"0").unwrap();

        while let Ok(event) = rx.recv().await {
            if let Ok(event) = event {
                let mut file_tx = File::create(backup_dir / event.path().file_name().unwrap().to_str().unwrap()).unwrap();
                file_tx.write_all(&event.content().unwrap()).unwrap();

                let timestamp = fs::metadata(&event.path()).unwrap().modified();
                fs::write(backup_dir / "file_timestamps", &timestamp.to_string()).unwrap();

                info!("Synchronized file: {:?}", event.path());
            }
        }
    });

    loop {
        sleep(Duration::from_secs(1)).await;

        let mut command = Command::new("logrotate");
        command.arg("-f");
        command.arg("/etc/logrotate.conf");
        command.status().unwrap();
    }
}

async fn create_backup_dir(dir: &str) -> Result<(), io::Error> {
    if !dir.starts_with("/") {
        return Err(io::Error::new(io::ErrorKind::InvalidInput, "Invalid directory"));
    }

    let backup_dir = Path::new(dir).join(BACKUP_DIR);
    fs::create_dir_all(&backup_dir)?;

    fs::create_dir_all(Path::new(dir).join(WATCH_DIR))?;

    Ok(())
}

#[tokio::main]
async fn main() {
    env_logger::init();

    run().await;
}
