use std::fs;
use std::io;
use std::path::{Path, PathBuf};
use std::thread;
use std::time::Duration;

fn organize_files(dir: &Path) {
    for entry in fs::read_dir(dir).unwrap() {
        let entry = entry.unwrap();
        let path = entry.path();
        if path.is_file() {
            let extension = path.extension().unwrap().to_str().unwrap();
            let new_dir = format!("{}/{}", dir.display(), extension);
            let new_dir_path = Path::new(&new_dir);
            if !new_dir_path.exists() {
                fs::create_dir_all(&new_dir_path).unwrap();
            }
            let src = path.to_string_lossy();
            let dst = new_dir_path.join(src);
            if !dst.exists() {
                fs::copy(&path, &dst).unwrap();
                println!("Moved {} to {}", src, dst.display());
            }
        }
    }
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <directory>", args[0]);
        std::process::exit(1);
    }
    let dir = Path::new(&args[1]);
    if !dir.exists() {
        eprintln!("Error: The directory {} does not exist.", args[1]);
        std::process::exit(1);
    }
    let mut handles = vec![];
    for _ in 0..10 {
        let dir_clone = dir.clone();
        let handle = thread::spawn(move || {
            organize_files(&dir_clone);
        });
        handles.push(handle);
    }
    for handle in handles {
        handle.join().unwrap();
    }
}
