        .lines()
        .map(|line| line.expect("failed to read line"))
        .map(|line| Stock::from_str(&line))
        .collect();

    let store_data = Arc::new(Mutex::new(data));

    tokio::spawn(async move {
        tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;

        let store_data = store_data.clone();
        tokio::spawn(async move {
            let mut writer = BufWriter::new(file);
            let data: Vec<Stock> = store_data.lock().unwrap().clone();
            writer
                .write_all(serde_json::to_string(&data).unwrap().as_bytes())
                .expect("failed to write data");
            writer.flush().expect("failed to flush data");
        });
    });

    loop {
