import javax.ws.rs.*;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;
import java.io.IOException;
import java.util.concurrent.atomic.AtomicReference;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.dataformat.json.JsonProcessingException;
import edu.stanford.nlp.ling.CoreAnnotations;
import edu.stanford.nlp.neural.rnn.RNNCoreAnnotations;
import edu.stanford.nlp.pipeline.Annotation;
import edu.stanford.nlp.pipeline.StanfordCoreNLP;
import edu.stanford.nlp.sentiment.SentimentCoreAnnotations;
import edu.stanford.nlp.trees.Tree;
import edu.stanford.nlp.util.CoreMap;

import java.util.Properties;

@Path("/sentiment")
public class SentimentAnalysisService {

    private StanfordCoreNLP pipeline;

    public SentimentAnalysisService() {
        Properties props = new Properties();
        props.setProperty("annotators", "tokenize, ssplit, parse, sentiment");
        this.pipeline = new StanfordCoreNLP(props);
    }

    @POST
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response analyzeSentiment(String text) {
        try {
            AtomicReference<String> sentiment = new AtomicReference<>();
            JsonNode json = new ObjectMapper().readTree(text);
            if (json.has("text")) {
                String textToAnalyze = json.get("text").asText();
                Annotation annotation = pipeline.process(textToAnalyze);
                for (CoreMap sentence : annotation.get(CoreAnnotations.SentencesAnnotation.class)) {
                    Tree tree = sentence.get(SentimentCoreAnnotations.SentimentAnnotatedTree.class);
                    int sentimentType = RNNCoreAnnotations.getPredictedClass(tree);
                    String sentimentLabel;
                    if (sentimentType == 0) {
                        sentimentLabel = "negative";
                    } else if (sentimentType == 1) {
                        sentimentLabel = "neutral";
                    } else {
                        sentimentLabel = "positive";
                    }
                    sentiment.set(sentimentLabel);
                }
            }
            return Response.ok(new JsonNode("{\"sentiment\": \"" + sentiment.get() + "\"}"))
                    .type(MediaType.APPLICATION_JSON)
                    .build();
        } catch (IOException | JsonProcessingException e) {
            return Response.serverError().build();
        }
    }
}
