use std::collections::HashMap;
use std::fs::File;
use std::io::{BufReader, BufWriter, Read, Write};
use std::path::Path;
use tokio;
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::oneshot;
use tokio_util::codec::{AsyncBufReader, AsyncBufWriter};
use tokio::prelude::*;

async fn handle_client(mut stream: TcpStream) {
    let reader = AsyncBufReader::new(stream);
    let writer = AsyncBufWriter::new(stream);

    let mut chat_history = load_chat_history();

    loop {
        let mut message = String::new();
        reader.read_line(&mut message).await.unwrap();

        if message.trim().is_empty() {
            break;
        }

        let recipient = message.trim().split(" ").next().unwrap();
        message = message.trim().replace(&[recipient].join(" "), "");

        chat_history[&recipient].push(message);

        write!(writer, "{}: {}", recipient, message).await.unwrap();
        writer.write_all(format!("\n").as_bytes()).await.unwrap();
    }

    writer.flush().await.unwrap();

    chat_history[&recipient].push(format!("Client disconnected"));
    save_chat_history(chat_history);
}

async fn save_chat_history(chat_history: HashMap<String, Vec<String>>) {
    let mut file = File::create("chat_history.txt").unwrap();
    for (recipient, messages) in &chat_history {
        for message in messages {
            file.write_all(message.as_bytes()).unwrap();
            file.write_all("\n".as_bytes()).unwrap();
        }
    }
}

async fn load_chat_history() -> HashMap<String, Vec<String>> {
    let mut file = File::open("chat_history.txt").unwrap();
    let mut chat_history = HashMap::new();
    let mut line = String::new();
    while let Ok(0) = file.read_line(&mut line) {
        let recipient = line.trim().split(" ").next().unwrap();
        chat_history.insert(recipient.to_string(), Vec::new());
        line.clear();
    }
    chat_history
}

#[tokio::main]
async fn main() {
    let listener = TcpListener::bind("127.0.0.1:8080").await.unwrap();
    println!("Server listening on port 8080");

    let mut chat_history = HashMap::new();

    for stream in listener.incoming() {
        match stream {
            Ok(stream) => {
                tokio::spawn(handle_client(stream));
            }
            Err(e) => {
                println!("Error: {}", e);
            }
        }
    }
}
