public class DataRetentionService {

    private final String databaseType;
    private final String dbUrl;
    private final String dbUser;
    private final String dbPassword;
    private final Map<String, Long> retentionDurations;
    private final ExecutorService executorService;

    public DataRetentionService(String databaseType, String dbUrl, String dbUser, String dbPassword, Map<String, Long> retentionDurations) {
        this.databaseType = databaseType;
        this.dbUrl = dbUrl;
        this.dbUser = dbUser;
        this.dbPassword = dbPassword;
        this.retentionDurations = retentionDurations;
        this.executorService = Executors.newSingleThreadExecutor();
    }

    public void start() {
        if (databaseType.equalsIgnoreCase("sql")) {
            startSqlDatabase();
        } else if (databaseType.equalsIgnoreCase("nosql")) {
            startNosqlDatabase();
        } else {
            throw new UnsupportedOperationException("Unsupported database type");
        }
    }

    private void startSqlDatabase() {
        try (Connection conn = DriverManager.getConnection(dbUrl, dbUser, dbPassword)) {
            Statement stmt = conn.createStatement();
            for (Map.Entry<String, Long> entry : retentionDurations.entrySet()) {
                String tableName = entry.getKey();
                long retentionDuration = entry.getValue();

                stmt.execute("CREATE TABLE IF NOT EXISTS " + tableName + " (id INT PRIMARY KEY, data VARCHAR(255))");

                executorService.submit(() -> {
                    try (Statement purgeStmt = conn.createStatement()) {
                        purgeStmt.execute("DELETE FROM " + tableName + " WHERE id > (SELECT COUNT(*) FROM " + tableName + ") - " + retentionDuration);
                    } catch (SQLException e) {
                        System.err.println("Error purging data from table " + tableName + ": " + e.getMessage());
                    }
                });
            }
        } catch (SQLException e) {
            System.err.println("Error connecting to database: " + e.getMessage());
        }
    }

    private void startNosqlDatabase() {
        try {
            // Implement your NoSQL database driver here
            // For example, using MongoDB
            MongoDB mongoDB = new MongoDB(dbUrl, dbUser, dbPassword);
            for (Map.Entry<String, Long> entry : retentionDurations.entrySet()) {
                String tableName = entry.getKey();
                long retentionDuration = entry.getValue();

                mongoDB.purgeCollection(tableName, retentionDuration);
            }
        } catch (Exception e) {
            System.err.println("Error connecting to database: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        Map<String, Long> retentionDurations = new HashMap<>();
        retentionDurations.put("table1", 30 * 24 * 60 * 60 * 1000); // 30 days
        retentionDurations.put("table2", 60 * 24 * 60 * 60 * 1000); // 1 month

        DataRetentionService service = new DataRetentionService("sql", "jdbc:mysql://localhost:3306/mydb", "myuser", "mypassword", retentionDurations);
        service.start();
    }
}

