use std::fs;
use std::path::Path;
use std::sync::Arc;
use tokio;
use tokio::prelude::*;
use tokio::sync::Mutex;

use serde::{Deserialize, Serialize};
use bincode;

#[derive(Deserialize, Serialize)]
struct LogData {
    data: String,
}

async fn migrate_log_file(file_path: &str) -> Result<(), Box<dyn std::error::Error>> {
    let log_data: LogData = serde_json::from_str(&fs::read_to_string(file_path)?)?;
    let serialized_data = bincode::serialize(&log_data)?;
    fs::write(format!("{}.bin", file_path), serialized_data)?;
    Ok(())
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let directory_path = "path_to_your_directory";
    let directory_path = Path::new(directory_path);
    let mut handles = Vec::new();

    for entry in directory_path.read_dir()? {
        let entry = entry?;
        if entry.file_name().to_str().unwrap().ends_with(".log") {
            let file_path = entry.path();
            let file_path = Arc::new(file_path);
            let file_path_clone = file_path.clone();
            let handle = tokio::spawn(migrate_log_file(&file_path_clone).await);
            handles.push(handle);
        }
    }

    for handle in handles {
        handle.await?;
    }

    Ok(())
}
