import java.io.BufferedReader;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.*;

public class CSVTool {

    public static void main(String[] args) {
        if (args.length == 0) {
            System.out.println("Usage: java CSVTool <input_file> <output_file> <config_file>");
            return;
        }

        String inputFile = args[0];
        String outputFile = args[1];
        String configFile = args[2];

        Map<String, String> config = readConfig(configFile);

        processCSV(inputFile, outputFile, config);
    }

    private static Map<String, String> readConfig(String configFile) {
        Map<String, String> config = new HashMap<>();
        try (BufferedReader reader = new BufferedReader(new FileReader(configFile))) {
            String line;
            while ((line = reader.readLine()) != null) {
                String[] parts = line.split("=");
                if (parts.length == 2) {
                    config.put(parts[0].trim(), parts[1].trim());
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading config file: " + e.getMessage());
            System.exit(1);
        }
        return config;
    }

    private static void processCSV(String inputFile, String outputFile, Map<String, String> config) {
        try (BufferedReader reader = new BufferedReader(new FileReader(inputFile))) {
            List<String[]> rows = new ArrayList<>();
            String line;
            while ((line = reader.readLine()) != null) {
                String[] parts = line.split(",");
                rows.add(parts);
            }

            // Check data consistency
            if (config.containsKey("check_consistency")) {
                checkDataConsistency(rows, config);
            }

            // Remove duplicates
            if (config.containsKey("remove_duplicates")) {
                removeDuplicates(rows, config);
            }

            // Re-order columns
            if (config.containsKey("reorder_columns")) {
                reOrderColumns(rows, config);
            }

            // Write to output file
            try (BufferedWriter writer = new BufferedWriter(new FileWriter(outputFile))) {
                for (String[] row : rows) {
                    for (String column : row) {
                        writer.write(column + ",");
                    }
                    writer.write("\n");
                }
            }
        } catch (IOException e) {
            System.err.println("Error processing CSV file: " + e.getMessage());
            System.exit(1);
        }
    }

    private static void checkDataConsistency(List<String[]> rows, Map<String, String> config) {
        // Check for missing values
        if (config.containsKey("check_missing_values")) {
            for (String[] row : rows) {
                boolean hasMissingValue = false;
                for (String column : row) {
                    if (column.isEmpty()) {
                        hasMissingValue = true;
                        break;
                    }
                }
                if (hasMissingValue) {
                    System.out.println("Row contains missing values");
                }
            }
        }

        // Check for duplicate rows
        if (config.containsKey("check_duplicate_rows")) {
            Set<String> uniqueRows = new HashSet<>();
            for (String[] row : rows) {
                String rowKey = Arrays.toString(row);
                if (!uniqueRows.add(rowKey)) {
                    System.out.println("Duplicate row found");
                }
            }
        }
    }

    private static void removeDuplicates(List<String[]> rows, Map<String, String> config) {
        // Remove duplicate rows
        if (config.containsKey("remove_duplicates")) {
            Set<String[]> uniqueRows = new HashSet<>();
            List<String[]> filteredRows = new ArrayList<>();
            for (String[] row : rows) {
                String rowKey = Arrays.toString(row);
                if (!uniqueRows.add(row)) {
                    filteredRows.add(row);
                }
            }
            rows = filteredRows;
        }
    }

    private static void reOrderColumns(List<String[]> rows, Map<String, String> config) {
        // Re-order columns
        if (config.containsKey("reorder_columns")) {
            String[] columnNames = config.get("reorder_columns").split(",");
            List<String[]> reorderedRows = new ArrayList<>();
            for (String[] row : rows) {
                List<String> reorderedRow = new ArrayList<>();
                for (String columnName : columnNames) {
                    reorderedRow.add(row[Arrays.asList(columnNames).indexOf(columnName)]);
                }
                reorderedRows.add(reorderedRow.toArray(new String[0]));
            }
            rows = reorderedRows;
        }
    }
}
