use tokio::net::TcpListener;
use tokio::prelude::*;
use tokio::sync::mpsc;
use tokio::task;
use std::env;
use std::fs;
use std::io;
use std::path::PathBuf;
use std::sync::Arc;

#[tokio::main]
async fn main() {
    // Create a TCP listener on port 8080
    let listener = TcpListener::bind("127.0.0.1:8080").await.unwrap();

    // Create channels for incoming requests and responses
    let (tx, rx) = mpsc::channel(10);

    // Spawn tasks for incoming requests
    task::spawn_all(vec![
        tokio::spawn(async move {
            let (stream, _) = listener.accept().await.unwrap();
            let mut buffer = [0; 4096];
            loop {
                let n = stream.read(&mut buffer).await.unwrap();
                if n == 0 {
                    break;
                }
                let response = format!("HTTP/1.1 200 OK\r\nContent-Type: {}\r\n\r\n{}", get_mime_type(), std::str::from_utf8(&buffer[..n]).unwrap());
                stream.write_all(response.as_bytes()).await.unwrap();
                stream.flush().await.unwrap();
            }
            tx.send(()).unwrap();
        }),
        tokio::spawn(async move {
            loop {
                let request = rx.recv().await.unwrap();
                println!("Request received");
                tx.send(()).unwrap();
            }
        }),
    ]);

    // Handle incoming requests
    for _ in 0..10 {
        let request = rx.recv().await.unwrap();
        println!("Request received");
        tx.send(()).unwrap();
    }

    // Wait for incoming requests to finish
    task::block_on(async {
        for _ in 0..10 {
            rx.recv().await.unwrap();
        }
    });
}

fn get_mime_type(path: &PathBuf) -> String {
    let mime_type = match path.extension().and_then(|ext| ext.to_str()) {
        Some("txt") => "text/plain".to_string(),
        Some("jpg") => "image/jpeg".to_string(),
        Some("png") => "image/png".to_string(),
        _ => "application/octet-stream".to_string(),
    };
    mime_type
