const SMTP_PASSWORD: &str = "your-smtp-password";
const FROM_EMAIL: &str = "your-email";

#[async_trait]
trait EmailSender {
    async fn send_email(&self, subject: &str, body: &str) -> io::Result<()>;
}

struct SmtpEmailSender {
    username: String,
    password: String,
}

impl SmtpEmailSender {
    fn new(username: String, password: String) -> Self {
        SmtpEmailSender { username, password }
    }
}

#[async_trait]
impl EmailSender for SmtpEmailSender {
    async fn send_email(&self, subject: &str, body: &str) -> io::Result<()> {
        let mut client = tokio_tungstenite::connect_async(
            format!("smtp://{}:{}", SMTP_SERVER, SMTP_PORT),
        )
        .await?;

        let mut stream = client.send(Message::new(MessageStream::Text(body.clone()))).await?;

        stream.write(Message::new(MessageStream::Text(format!("From: {}\r\n", FROM_EMAIL).as_bytes()))).await?;

        stream.write(Message::new(MessageStream::Text(format!("To: {}\r\n", FROM_EMAIL).as_bytes()))).await?;

        stream.write(Message::new(MessageStream::Text(format!("Subject: {}\r\n", subject).as_bytes()))).await?;

        stream.write(Message::new(MessageStream::Text(format!("MIME-Version: 1.0\r\n\r\n", "").as_bytes()))).await?;

        stream.write(Message::new(MessageStream::Text(format!("Content-Type: text/plain; charset=\"utf-8\"\r\n\r\n", "").as_bytes()))).await?;

        stream.write(Message::new(MessageStream::Text(format!("Content-Transfer-Encoding: base64\r\n", "").as_bytes()))).await?;

        stream.write(Message::new(MessageStream::Text(format!("Content-Disposition: inline; filename=\"{}\"\r\n", Uuid::new_v4().to_string().as_str()).as_bytes()))).await?;

        stream.write(Message::new(MessageStream::Text(format!("\r\n", "").as_bytes()))).await?;

        let mut buf = Vec::new();
        stream.read_to_end(&mut buf).await?;
        Ok(())
    }
}

#[tokio::main]
async fn main() -> io::Result<()> {
    let mut args = env::args();
    args.next(); // Skip the program name

    let mut config = HashMap::new();

    for arg in args {
        let mut parts = arg.splitn(2, '=');
        let key = parts.next().unwrap();
        let value = parts.next().unwrap();

        match key.as_str() {
            "--dir" => config.insert("dir", value),
            "--port" => config.insert("port", value),
            "--username" => config.insert("username", value),
            "--password" => config.insert("password", value),
            "--subject" => config.insert("subject", value),
            "--body" => config.insert("body", value),
            "--from-email" => config.insert("from-email", value),
            _ => panic!("Unknown argument: {}", arg),
        }
    }

    let dirs = config.get("dir").unwrap().split(',').map(|s| s.to_string()).collect::<Vec<_>>();

    let smtp = SmtpEmailSender::new(config.get("username").unwrap().to_string(), config.get("password").unwrap().to_string());

    let mut file_system = tokio::fs::OpenOptions::new()
        .read(true)
        .write(true)
        .create(true)
        .open(config.get("dir").unwrap().clone())
        .await?;

    let mut changed_files = HashMap::new();

    tokio::spawn(async move {
        while let Some(entry) = file_system.read_dir().await? {
            for entry in entry {
                let entry_path = entry.path();
                if entry_path.is_file() {
                    let file_path = entry_path.to_str().unwrap().to_string();
                    if let Some(file) = file_system.read_file(file_path).await {
                        let file_content = String::from_utf8(file).unwrap();
                        if changed_files.contains_key(&file_path) {
                            if file_content != changed_files.get(&file_path).unwrap() {
                                changed_files.insert(file_path, file_content.clone());
                                tokio::spawn(async move {
                                    smtp.send_email(config.get("subject").unwrap().to_string().as_str(), format!("New file detected: {}\n{}", file_path, file_content).as_str()).await?;
                                });
                            }
                        } else {
                            changed_files.insert(file_path, file_content.clone());
                        }
                    }
                }
            }
        }
    });

    while let Some(entry) = file_system.read_dir().await? {
        for entry in entry {
            let entry_path = entry.path();
            if entry_path.is_file() {
                let file_path = entry_path.to_str().unwrap().to_string();
                if !changed_files.contains_key(&file_path) {
                    changed_files.insert(file_path, String::new());
                }
            }
        }
    }

    Ok(())
