class TaskDatabase:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()
        self.cursor.execute('''
            CREATE TABLE IF NOT EXISTS tasks
            (id INTEGER PRIMARY KEY AUTOINCREMENT, description TEXT, deadline DATE, completed INTEGER)
        ''')

    def add_task(self, description, deadline, completed=0):
        self.cursor.execute('INSERT INTO tasks (description, deadline, completed) VALUES (?, ?, ?)', (description, deadline, completed))
        self.conn.commit()

    def update_task(self, id, description=None, deadline=None, completed=None):
        if description:
            self.cursor.execute('UPDATE tasks SET description = ? WHERE id = ?', (description, id))
        if deadline:
            self.cursor.execute('UPDATE tasks SET deadline = ? WHERE id = ?', (deadline, id))
        if completed:
            self.cursor.execute('UPDATE tasks SET completed = ? WHERE id = ?', (completed, id))
        self.conn.commit()

    def delete_task(self, id):
        self.cursor.execute('DELETE FROM tasks WHERE id = ?', (id,))
        self.conn.commit()

    def get_tasks(self, deadline=None, completed=None):
        query = 'SELECT * FROM tasks'
        params = []
        if deadline:
            query += ' WHERE deadline = ?'
            params.append(deadline)
        if completed:
            query += ' AND completed = ?'
            params.append(completed)
        self.cursor.execute(query, params)
        return [dict(zip(['id', 'description', 'deadline', 'completed'], row)) for row in self.cursor.fetchall()]

    def get_tasks_by_id(self, ids):
        self.cursor.execute('SELECT * FROM tasks WHERE id IN ?', (tuple(ids),))
        return [dict(zip(['id', 'description', 'deadline', 'completed'], row)) for row in self.cursor.fetchall()]

    def close(self):
        self.conn.close()


