use std::fs::File;
use std::io::{BufWriter, Write};
use std::path::Path;
use std::thread;
use std::time::{Duration, Instant};

use async_trait::async_trait;
use tokio::{select, task};
use tokio::sync::mpsc;
use tokio::time::{sleep, timeout};
use tokio_util::sync::mpsc::{Receiver, Sender};

use crossbeam_channel;
use crossbeam_channel::{Sender, Receiver};

use std::process;
use std::env;

const LOG_FILE: &str = "system_resources.log";

#[async_trait]
trait SystemResourceChecker {
    async fn cpu_usage(&self) -> f64;
    async fn memory_usage(&self) -> u64;
    async fn disk_usage(&self) -> u64;
}

struct CpuChecker;

#[async_trait]
impl SystemResourceChecker for CpuChecker {
    async fn cpu_usage(&self) -> f64 {
        let start = Instant::now();
        let _ = std::thread::sleep(Duration::from_millis(100));
        let end = Instant::now();
        let duration = end.duration_since(start);
        let cpu_usage = (duration.as_nanos() as f64) / 1e9 / (duration.as_secs() as f64);
        cpu_usage
    }

    async fn memory_usage(&self) -> u64 {
        let total = std::process::output("free -m").unwrap().stdout;
        let lines = total.split("\n");
        let mut line = lines.next().unwrap();
        let values = line.split_whitespace();
        let memory_total: u64 = values.next().unwrap().parse().unwrap();
        let memory_used: u64 = values.next().unwrap().parse().unwrap();
        memory_total - memory_used
    }

    async fn disk_usage(&self) -> u64 {
        let total = std::process::output("df -k --output=avail").unwrap().stdout;
        let lines = total.split("\n");
        let mut line = lines.next().unwrap();
        let values = line.split_whitespace();
        let disk_total: u64 = values.next().unwrap().parse().unwrap();
        let disk_used: u64 = disk_total - values.next().unwrap().parse().unwrap();
        disk_used
    }
}

struct MemoryChecker;

#[async_trait]
impl SystemResourceChecker for MemoryChecker {
    async fn cpu_usage(&self) -> f64 {
        0.0
    }

    async fn memory_usage(&self) -> u64 {
        CpuChecker::memory_usage().await
    }

    async fn disk_usage(&self) -> u64 {
        CpuChecker::disk_usage().await
    }
}

struct DiskChecker;

#[async_trait]
impl SystemResourceChecker for DiskChecker {
    async fn cpu_usage(&self) -> f64 {
        0.0
    }

    async fn memory_usage(&self) -> u64 {
        CpuChecker::memory_usage().await
    }

    async fn disk_usage(&self) -> u64 {
        CpuChecker::disk_usage().await
    }
}

struct SystemResources {
    cpu_checker: Box<dyn SystemResourceChecker>,
    memory_checker: Box<dyn SystemResourceChecker>,
    disk_checker: Box<dyn SystemResourceChecker>,
    log_file: String,
}

impl SystemResources {
    fn new(log_file: String) -> Self {
        let cpu_checker = Box::new(CpuChecker);
        let memory_checker = Box::new(MemoryChecker);
        let disk_checker = Box::new(DiskChecker);
        Self { cpu_checker, memory_checker, disk_checker, log_file }
    }
}

impl SystemResources {
    async fn start(&self) {
        let (tx, rx) = crossbeam_channel::unbounded();
        let (tx, tx2) = crossbeam_channel::unbounded();
        let (tx, tx3) = crossbeam_channel::unbounded();

        task::spawn(async move {
            loop {
                let cpu_usage = self.cpu_checker.cpu_usage().await;
                let memory_usage = self.memory_checker.memory_usage().await;
                let disk_usage = self.disk_checker.disk_usage().await;
                tx.send((cpu_usage, memory_usage, disk_usage)).unwrap();
                sleep(Duration::from_secs(60)).await;
            }
        });

        task::spawn(async move {
            loop {
                match rx.recv().await {
                    Ok((cpu_usage, memory_usage, disk_usage)) => {
                        let log_entry = format!("{};{};{};{}", cpu_usage, memory_usage, disk_usage, std::time::SystemTime::now().duration_since(std::time::SystemTime::UNIX_EPOCH).unwrap().as_secs());
                        let log_file_path = Path::new(&self.log_file);
                        let mut file = match File::create(log_file_path) {
                            Ok(file) => file,
                            Err(_) => return,
                        };
                        let mut writer = BufWriter::new(file);
                        writeln!(writer, "{}", log_entry).unwrap();
                        writer.flush().unwrap();
                    },
                    Err(_) => {}
                }
            }
        });

        task::spawn(async move {
            loop {
                match tx2.recv().await {
                    Ok((cpu_usage, memory_usage, disk_usage)) => {
                        let log_entry = format!("{};{};{};{}", cpu_usage, memory_usage, disk_usage, std::time::SystemTime::now().duration_since(std::time::SystemTime::UNIX_EPOCH).unwrap().as_secs());
                        let log_file_path = Path::new(&LOG_FILE);
                        let mut file = match File::create(log_file_path) {
                            Ok(file) => file,
                            Err(_) => return,
                        };
                        let mut writer = BufWriter::new(file);
                        writeln!(writer, "{}", log_entry).unwrap();
                        writer.flush().unwrap();
                    },
                    Err(_) => {}
                }
            }
        });

        task::spawn(async move {
            loop {
                match tx3.recv().await {
                    Ok((cpu_usage, memory_usage, disk_usage)) => {
                        let log_entry = format!("{};{};{};{}", cpu_usage, memory_usage, disk_usage, std::time::SystemTime::now().duration_since(std::time::SystemTime::UNIX_EPOCH).unwrap().as_secs());
                        let log_file_path = Path::new(&LOG_FILE);
                        let mut file = match File::create(log_file_path) {
                            Ok(file) => file,
                            Err(_) => return,
                        };
                        let mut writer = BufWriter::new(file);
                        writeln!(writer, "{}", log_entry).unwrap();
                        writer.flush().unwrap();
                    },
                    Err(_) => {}
                }
            }
        });
    }
}

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        println!("Usage: {} <log_file>", args[0]);
        std::process::exit(1);
    }
    let log_file = args[1].clone();
    let system_resources = SystemResources::new(log_file);
    system_resources.start().await;
}
