import org.java_websocket.drafts.Draft_11;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;

public class SystemResourceMonitor {

    private static final Logger logger = Logger.getLogger(SystemResourceMonitor.class.getName());

    private static final String CONFIG_SERVER_URL = "http://localhost:8080/config";
    private static final int CPU_THRESHOLD = 80;
    private static final int MEM_THRESHOLD = 80;

    private static final String JSON_LOG_FORMAT = "%1$tF %1$tT - %2$s - %3$s - %4$s%n";

    public static void main(String[] args) {
        // Initialize logging
        logger.setLevel(Level.ALL);
        ConsoleHandler consoleHandler = new ConsoleHandler();
        consoleHandler.setLevel(Level.ALL);
        consoleHandler.setFormatter(new SimpleFormatter(JSON_LOG_FORMAT));
        logger.addHandler(consoleHandler);

        // Create HTTP client
        WebSocketFactory webSocketFactory = new WebSocketFactory();
        webSocketFactory.setDraft(Draft_11.class);

        // Connect to configuration server
        WebSocket webSocket = webSocketFactory.connect(CONFIG_SERVER_URL);
        webSocket.onOpen(() -> System.out.println("Connected to configuration server"));
        webSocket.onMessage(message -> {
            try {
                ObjectMapper objectMapper = new ObjectMapper();
                ObjectNode config = objectMapper.readTree(message);
                if (config.has("cpuThreshold")) {
                    CPU_THRESHOLD = config.get("cpuThreshold").asInt();
                }
                if (config.has("memThreshold")) {
                    MEM_THRESHOLD = config.get("memThreshold").asInt();
                }
                System.out.println("Updated thresholds: CPU=" + CPU_THRESHOLD + "%, MEM=" + MEM_THRESHOLD + "%");
            } catch (Exception e) {
                logger.log(Level.SEVERE, "Error parsing configuration message", e);
            }
        });
        webSocket.onClose(event -> System.out.println("Disconnected from configuration server"));

        // Monitor system resources
        while (true) {
            long startTime = System.currentTimeMillis();
            double cpuUsage = getCPUUsage();
            double memUsage = getMemoryUsage();
            logger.info(String.format(JSON_LOG_FORMAT, new Date(), "CPU", cpuUsage, "Utilization exceeded threshold: " + (cpuUsage > CPU_THRESHOLD ? "true" : "false")));
            logger.info(String.format(JSON_LOG_FORMAT, new Date(), "MEM", memUsage, "Utilization exceeded threshold: " + (memUsage > MEM_THRESHOLD ? "true" : "false")));
            if (cpuUsage > CPU_THRESHOLD || memUsage > MEM_THRESHOLD) {
                sendAlert("CPU/MEM utilization exceeded threshold");
            }
            try {
                Thread.sleep(1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
            }
        }
    }

    private static double getCPUUsage() {
        // This method should return the current CPU usage
        // For simplicity, assume it returns a value between 0 and 100
        return Math.random() * 100;
    }

    private static double getMemoryUsage() {
        // This method should return the current memory usage
        // For simplicity, assume it returns a value between 0 and 100
        return Math.random() * 100;
    }

    private static void sendAlert(String alertMessage) {
        try {
            WebSocket webSocket = new WebSocket("ws://localhost:8080/alert");
            webSocket.send(alertMessage);
            webSocket.close();
        } catch (WebSocketException e) {
            logger.log(Level.SEVERE, "Error sending alert", e);
        }
    }
}
