fn notify_handler(event: &notify::Event) {
    match event {
        notify::Event::Create(path) => {
            let timestamp = Local::now().format("%Y-%m-%d %H:%M:%S").to_string();
            println!("{} Created: {}", timestamp, path.display());
            fs::OpenOptions::new()
                .append(true)
                .create(true)
                .open(log_file.clone())
                .unwrap()
                .write_all(format!("{} Created: {}\n", timestamp, path.display()).as_bytes())
                .unwrap();
        }
        notify::Event::Modify(path) => {
            let timestamp = Local::now().format("%Y-%m-%d %H:%M:%S").to_string();
            println!("{} Modified: {}", timestamp, path.display());
            fs::OpenOptions::new()
                .append(true)
                .create(true)
                .open(log_file.clone())
                .unwrap()
                .write_all(format!("{} Modified: {}\n", timestamp, path.display()).as_bytes())
                .unwrap();
        }
        notify::Event::Delete(path) => {
            let timestamp = Local::now().format("%Y-%m-%d %H:%M:%S").to_string();
            println!("{} Deleted: {}", timestamp, path.display());
            fs::OpenOptions::new()
                .append(true)
                .create(true)
