use std::collections::HashMap;
use std::error::Error;
use std::fmt;
use std::io;
use std::net::{TcpListener, TcpStream};
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::Duration;
use serde_json::json;
use log::{info, error};

struct KeyValueStore {
    store: Arc<Mutex<HashMap<String, i32>>>,
}

impl KeyValueStore {
    fn new() -> Self {
        KeyValueStore {
            store: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn update(&self, key: &str, value: i32) {
        *self.store.lock().unwrap().entry(key.to_string()).or_insert(0) += value;
    }

    fn get(&self, key: &str) -> Option<i32> {
        self.store.lock().unwrap().get(key).cloned()
    }
}

impl fmt::Display for KeyValueStore {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{}", serde_json::to_string(&self.store.lock().unwrap()).unwrap())
    }
}

fn handle_request(stream: TcpStream) {
    let mut store = KeyValueStore::new();

    let mut buffer = [0; 1024];
    stream.read(&mut buffer).unwrap();

    let json = unsafe { String::from_utf8_unchecked(buffer) };
    let data: serde_json::Value = match serde_json::from_str(&json) {
        Ok(value) => value,
        Err(_) => {
            error!("Malformed JSON");
            return;
        }
    };

    if let Some(key) = data.get("key") {
        if let Some(value) = data.get("value") {
            let value = value.as_i64().unwrap();
            store.update(key.as_str(), value);
        } else {
            error!("Missing value in request");
        }
    } else {
        error!("Missing key in request");
    }

    let response = serde_json::json!({
        "message": "Key-value pair updated",
        "store": store,
    });

    let mut response_bytes = serde_json::to_string(&response).unwrap();
    stream.write_all(response_bytes.as_bytes()).unwrap();
    stream.flush().unwrap();
}

fn main() {
    env_logger::init();

    let store = Arc::new(Mutex::new(HashMap::new()));

    let listener = TcpListener::bind("127.0.0.1:8080").unwrap();

    for stream in listener.incoming() {
        match stream {
            Ok(mut stream) => {
                thread::spawn(move || handle_request(stream));
            }
            Err(e) => {
                error!("Error accepting incoming connection: {}", e);
            }
        }
    }
}
