import java.net.http.HttpResponse;
import java.util.*;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

public class AnalyticsEngine {

    private static final String DB_URL = "jdbc:sqlite:analytics.db";
    private static final String API_URL = "https://your-rest-api.com/transactions";

    public static void main(String[] args) throws Exception {
        // Initialize the executor service for concurrent tasks
        ExecutorService executor = Executors.newFixedThreadPool(5);

        // Fetch data from the API and process it
        CompletableFuture<Void> apiTask = CompletableFuture.runAsync(() -> {
            fetchAndProcessData();
        }, executor);

        // Wait for the API task to complete
        apiTask.join();

        // Close the executor service
        executor.shutdown();
    }

    private static void fetchAndProcessData() throws Exception {
        // Create a connection to the SQLite database
        try (Connection conn = DriverManager.getConnection(DB_URL)) {
            // Create a statement to execute SQL queries
            try (Statement stmt = conn.createStatement()) {
                // Create a table to store the results if it doesn't exist
                stmt.execute("CREATE TABLE IF NOT EXISTS results (id INTEGER PRIMARY KEY, sum REAL, average REAL, max REAL)");

                // Fetch data from the API
                HttpClient client = HttpClient.newHttpClient();
                HttpRequest request = HttpRequest.newBuilder()
                        .uri(URI.create(API_URL))
                        .build();

                HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
                if (response.statusCode() == 200) {
                    // Parse the JSON response
                    ObjectMapper mapper = new ObjectMapper();
                    JsonNode json = mapper.readTree(response.body());

                    // Process the data
                    processTransactionData(json);
                } else {
                    System.out.println("Failed to fetch data from the API");
                }
            }
        }
    }

    private static void processTransactionData(JsonNode json) {
        // Initialize variables to store the results
        double sum = 0;
        double average = 0;
        double max = 0;

        // Iterate over each transaction in the JSON data
        for (JsonNode transaction : json.get("transactions").getValuesAsText()) {
            // Parse the transaction data
            double transactionSum = transaction.get("sum").asDouble();
            double transactionAverage = transaction.get("average").asDouble();
            double transactionMax = transaction.get("max").asDouble();

            // Update the results
            sum += transactionSum;
            average = sum / (json.get("transactions").asInt());
            max = Math.max(max, transactionMax);
        }

        // Store the results in the database
        try (Connection conn = DriverManager.getConnection(DB_URL)) {
            // Create a statement to execute SQL queries
            try (PreparedStatement pstmt = conn.prepareStatement("INSERT INTO results (sum, average, max) VALUES (?, ?, ?)")) {
                pstmt.setDouble(1, sum);
                pstmt.setDouble(2, average);
                pstmt.setDouble(3, max);
                pstmt.executeUpdate();
            }
        }
    }
}
