import java.util.logging.FileHandler;
import java.util.logging.Logger;
import java.util.logging.SimpleFormatter;

import org.apache.tesseract.js.Tesseract;
import org.apache.tesseract.js.TesseractException;

public class DirectoryMonitor {

    private static final Logger logger = Logger.getLogger(DirectoryMonitor.class.getName());
    private static final String TESSDATA_PREFIX = System.getProperty("user.home") + "/.tessdata";

    public static void main(String[] args) throws IOException {
        // Set up logging
        FileHandler fileHandler = new FileHandler("directory_monitor.log", true);
        logger.addHandler(fileHandler);
        fileHandler.setFormatter(new SimpleFormatter());

        // Create WatchService
        WatchService watchService = Files.newWatchService();

        // Create directory to monitor
        File directory = new File("/path/to/directory");
        directory.watch(watchService);

        // Register watch keys
        for (WatchKey key : watchService.take()()) {
            WatchEvent<?>[] events = key.pollEvents();
            for (WatchEvent<?> event : events) {
                Path path = (Path) event.context();
                if (path.isDirectory()) {
                    try {
                        logger.info("Directory changed: " + path);
                        processDirectory(path);
                    } catch (IOException e) {
                        logger.severe("Error processing directory: " + path + ", " + e.getMessage());
                    }
                } else if (path.isFile()) {
                    logger.info("File added: " + path);
                    processFile(path);
                }
            }
            key.reset();
        }

        // Shut down watch service
        watchService.shutdown();
    }

    private static void processDirectory(Path directory) throws IOException {
        Files.walk(directory).forEach(path -> {
            if (Files.isRegularFile(path)) {
                processFile(path);
            }
        });
    }

    private static void processFile(Path file) {
        try {
            // Extract text using Tesseract OCR
            Tesseract tesseract = new Tesseract();
            tesseract.setDatapath(TESSDATA_PREFIX);
            String text = tesseract.doOCR(file.toFile());

            // Save text to file with same name
            String fileName = file.getFileName().toString();
            String textFileName = fileName.substring(0, fileName.lastIndexOf('.')) + ".txt";
            try (FileWriter writer = new FileWriter(textFileName)) {
                writer.write(text);
                logger.info("Text saved to file: " + textFileName);
            } catch (IOException e) {
                logger.severe("Error saving text to file: " + textFileName + ", " + e.getMessage());
            }
        } catch (TesseractException e) {
            logger.severe("Error extracting text: " + e.getMessage());
        }
    }
}
