import java.time.LocalDate;
import java.time.format.DateTimeFormatter;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.Map;

import java.util.stream.Collectors;

import java.util.concurrent.atomic.AtomicLong;

public class StockMarketSimulation {

    public static class Stock {
        private final String symbol;
        private final double price;

        public Stock(String symbol, double price) {
            this.symbol = symbol;
            this.price = price;
        }

        public String getSymbol() {
            return symbol;
        }

        public double getPrice() {
            return price;
        }
    }

    public static class StockPriceRecord {
        private final LocalDate date;
        private final Stock stock;
        private final double price;

        public StockPriceRecord(LocalDate date, Stock stock, double price) {
            this.date = date;
            this.stock = stock;
            this.price = price;
        }

        public LocalDate getDate() {
            return date;
        }

        public Stock getStock() {
            return stock;
        }

        public double getPrice() {
            return price;
        }
    }

    public static class MarketScenario {
        private final String name;
        private final StockPriceRecord[] priceRecords;

        public MarketScenario(String name, StockPriceRecord[] priceRecords) {
            this.name = name;
            this.priceRecords = priceRecords;
        }

        public String getName() {
            return name;
        }

        public StockPriceRecord[] getPriceRecords() {
            return priceRecords;
        }
    }

    public static class MessagingSystem {
        private final HttpClient httpClient;
        private final ExecutorService executorService;
        private final Lock lock = new ReentrantLock();

        public MessagingSystem(HttpClient httpClient, ExecutorService executorService) {
            this.httpClient = httpClient;
            this.executorService = executorService;
        }

        public void sendMessage(String message) throws IOException, InterruptedException {
            executorService.submit(() -> {
                lock.lock();
                try {
                    sendHttpRequest(message);
                } finally {
                    lock.unlock();
                }
            });
        }

        private void sendHttpRequest(String message) throws IOException, InterruptedException {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create("https://example.com/market-updates"))
                    .header("Content-Type", "application/json")
                    .POST(HttpRequest.BodyPublishers.ofString(message))
                    .build();

            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

            if (response.statusCode() == 200) {
                System.out.println("Message sent successfully: " + message);
            } else {
                System.out.println("Failed to send message: " + response.statusCode());
            }
        }
    }

    public static class StockMarketSimulationApp {
        private final List<MarketScenario> marketScenarios;
        private final MessagingSystem messagingSystem;
        private final AtomicInteger currentMarketScenarioIndex;

        public StockMarketSimulationApp(List<MarketScenario> marketScenarios, MessagingSystem messagingSystem) {
            this.marketScenarios = marketScenarios;
            this.messagingSystem = messagingSystem;
            this.currentMarketScenarioIndex = new AtomicInteger(0);
        }

        public void startSimulation() {
            while (true) {
                if (currentMarketScenarioIndex.get() >= marketScenarios.size()) {
                    currentMarketScenarioIndex.set(0);
                }

                MarketScenario currentMarketScenario = marketScenarios.get(currentMarketScenarioIndex.get());
                StockPriceRecord[] priceRecords = currentMarketScenario.getPriceRecords();

                Random random = new Random();
                for (int i = 0; i < priceRecords.length; i++) {
                    double change = random.nextDouble() * 10 - 5;
                    priceRecords[i].setPrice(priceRecords[i].getPrice() + change);
                }

                messagingSystem.sendMessage("Market update: " + currentMarketScenario.getName());

                try {
                    Thread.sleep(1000);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }

                currentMarketScenarioIndex.incrementAndGet();
            }
        }

        public static void main(String[] args) {
            // Initialize stock prices
            StockPriceRecord[] stockPriceRecords = {
                    new StockPriceRecord(LocalDate.now(), new Stock("AAPL", 150.0), 150.0),
                    new StockPriceRecord(LocalDate.now(), new Stock("GOOG", 2500.0), 2500.0),
                    new StockPriceRecord(LocalDate.now(), new Stock("MSFT", 200.0), 200.0)
            };

            // Create market scenarios
            List<MarketScenario> marketScenarios = new ArrayList<>();
            marketScenarios.add(new MarketScenario("Bull Market", stockPriceRecords));
            marketScenarios.add(new MarketScenario("Bear Market", stockPriceRecords));
            marketScenarios.add(new MarketScenario("Crash", stockPriceRecords));

            // Create messaging system
            HttpClient httpClient = HttpClient.newHttpClient();
            ExecutorService executorService = Executors.newSingleThreadExecutor();

            MessagingSystem messagingSystem = new MessagingSystem(httpClient, executorService);

            // Start simulation
            StockMarketSimulationApp simulationApp = new StockMarketSimulationApp(marketScenarios, messagingSystem);
            simulationApp.startSimulation();
        }
    }
}
