public class CurrencyConverter {

    private static final String EXCHANGE_API_URL = "https://api.exchangerate-api.com/v4/latest/";
    private static final ConcurrentMap<String, Double> cache = new ConcurrentHashMap<>();

    public static void main(String[] args) throws IOException, InterruptedException {
        HttpClient client = HttpClient.newHttpClient();
        String endpoint = EXCHANGE_API_URL + System.getProperty("user.language").toLowerCase();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(endpoint))
                .GET()
                .build();

        HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
        JsonObject rates = Json.createObjectBuilder()
                .add("rates", Json.createObjectBuilder()
                        .build())
                .build();
        JsonObject data = Json.createObjectBuilder()
                .add("base", response.headers().firstValue("Content-Type").orElse("USD").toString())
                .add("date", response.headers().firstValue("Date").orElse(null))
                .add("rates", rates)
                .build();

        System.out.println(Json.createObjectBuilder()
                .add("data", data)
                .build());
    }

    public static double convert(double amount, String fromCurrency, String toCurrency) throws IOException, InterruptedException {
        String endpoint = EXCHANGE_API_URL + fromCurrency.toLowerCase();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(endpoint))
                .GET()
                .build();

        HttpResponse<String> response = HttpClient.newHttpClient().send(request, HttpResponse.BodyHandlers.ofString());
        JsonObject rates = Json.createObjectBuilder()
                .add("rates", Json.createObjectBuilder()
                        .build())
                .build();
        JsonObject data = Json.createObjectBuilder()
                .add("base", response.headers().firstValue("Content-Type").orElse("USD").toString())
                .add("date", response.headers().firstValue("Date").orElse(null))
                .add("rates", rates)
                .build();

        if (cache.containsKey(endpoint)) {
            return amount * cache.get(endpoint);
        }

        double rate = getRate(data);
        cache.put(endpoint, rate);
        return amount * rate;
    }

    private static double getRate(JsonObject data) {
        return data.getJsonObject("rates").getNumber("USD").getDoubleValue();
    }
}
