public class ServerHealthService extends HttpServlet {

    private static final long serialVersionUID = 1L;

    @Resource
    private ConcurrentMap<String, ServerHealthData> cache;

    @Resource
    private ScheduledExecutorService scheduler;

    @Override
    public void init() throws ServletException {
        cache = new ConcurrentHashMap<>();
        scheduler = Executors.newSingleThreadScheduledExecutor();
        scheduleHealthChecks();
    }

    private void scheduleHealthChecks() {
        scheduler.scheduleAtFixedRate(() -> {
            collectSystemMetrics();
            updateCache();
        }, 0, 1, TimeUnit.MINUTES);
    }

    private void collectSystemMetrics() {
        // Simulate collecting system metrics
        long memoryUsage = Runtime.getRuntime().totalMemory() - Runtime.getRuntime().freeMemory();
        double cpuLoad = Runtime.getRuntime().availableProcessors() * 100;
        long diskUsage = (long) (Runtime.getRuntime().totalMemory() - Runtime.getRuntime().freeMemory()) * 100;
        cache.put("memoryUsage", memoryUsage);
        cache.put("cpuLoad", cpuLoad);
        cache.put("diskUsage", diskUsage);
    }

    private void updateCache() {
        // Update the cache with the collected system metrics
    }

    @Override
    public void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        ServerHealthData healthData = cache.get("serverHealth");
        if (healthData != null) {
            response.setContentType("application/json");
            HttpEntity entity = new HttpEntity<>(healthData);
            response.getEntity().setContent(new byte[0]);
            response.getOutputStream().write(EntityUtils.toString(entity).getBytes());
