use serde::{Deserialize, Serialize};
use serde_json;
use std::fs::File;
use std::io::{BufReader, BufWriter, Read, Write};
use std::path::Path;
use tokio;

#[derive(Debug, Serialize, Deserialize)]
struct JsonSchema {
    properties: serde_json::Value,
    required: Vec<String>,
}

#[derive(Debug, Serialize, Deserialize)]
struct JsonFile {
    schema: JsonSchema,
    content: serde_json::Value,
}

async fn validate_json_schema(schema: &JsonSchema, content: serde_json::Value) -> Result<(), serde_json::Error> {
    if let Some(properties) = &schema.properties {
        let mut valid = true;
        for prop in properties.values() {
            if let Some(value) = prop.as_object() {
                for (key, value) in value {
                    if !schema.required.contains(&key) {
                        valid = false;
                        break;
                    }
                }
            }
        }
        if !valid {
            return Err(serde_json::error::Error::custom("JSON schema is not compatible with content"));
        }
    }
    Ok(())
}

async fn merge_json_files(file_paths: Vec<String>, output_path: String) -> Result<(), std::io::Error> {
    let mut output = BufWriter::new(File::create(output_path)?);
    let mut files = Vec::new();
    for file_path in file_paths {
        let file = File::open(file_path).await?;
        let reader = BufReader::new(file);
        let mut file_content = String::new();
        reader.read_to_string(&mut file_content).await?;
        files.push(serde_json::from_str(&file_content)?);
    }
    let merged_content = files
        .iter()
        .fold(serde_json::Value::Null, |merged, file| {
            merged.merge(file.content.clone(), serde_json::Merge::Replace).unwrap()
        });
    validate_json_schema(&files[0].schema, merged_content).await?;
    write!(output, "{}", serde_json::to_string(&merged_content)?).await?;
    Ok(())
}

#[tokio::main]
async fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 4 {
        eprintln!("Usage: {} <input_file1> <input_file2> ... <output_file>", args[0]);
        std::process::exit(1);
    }
    let input_file_paths: Vec<String> = args[1..3].into_iter().collect();
    let output_path = args[3].clone();
    merge_json_files(input_file_paths, output_path).await?;
}
