#[async_trait]
trait Fetcher {
    async fn fetch(&self) -> reqwest::Response;
}

#[async_trait]
trait Saver {
    async fn save(&self, response: reqwest::Response, filename: &str);
}

struct UrlFetcher;

#[async_trait]
impl Fetcher for UrlFetcher {
    async fn fetch(&self, url: &str) -> reqwest::Response {
        let client = reqwest::Client::new();
        client.get(url).send().await.unwrap()
    }
}

struct FileSaver;

#[async_trait]
impl Saver for FileSaver {
    async fn save(&self, response: reqwest::Response, filename: &str) {
        let hash = format!("{}", hash(response.url().to_string().as_str()));
        let file_path = format!("{}.txt", hash);
        let file = TokioFile::new(file_path).await.unwrap();
        let mut writer = BufWriter::new(file);
        response.write_to(&mut writer).await.unwrap();
        writer.flush().await.unwrap();
    }
}

#[tokio::main]
async fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 2 {
        eprintln!("Usage: {} <input_file>", args[0]);
        std::process::exit(1);
    }

    let input_file = args[1].clone();
    let file = File::open(input_file).unwrap();
    let reader = BufReader::new(file);

    for line in reader.lines() {
        let url = line.unwrap();
        let client = reqwest::Client::new();
        let response = client.get(&url).send().await.unwrap();
        let saver = FileSaver;
        let hash = format!("{}", hash(url));
        let file_path = format!("{}.txt", hash);
        let file = TokioFile::create(file_path).await.unwrap();
        saver.save(response, &file_path).await;
    }
}
