import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;

public class AnalyticsDaemon {

    public static void main(String[] args) {
        if (args.length < 2) {
            System.out.println("Usage: java -jar analytics-daemon.jar <log_file_path> <blacklist_url>");
            return;
        }

        String logFilePath = args[0];
        String blacklistUrl = args[1];

        Map<String, Integer> ipThreatScores = new HashMap<>();
        Scanner scanner = new Scanner(System.in);
        while (true) {
            try (BufferedReader reader = new BufferedReader(new FileReader(logFilePath))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    String[] parts = line.split(" ");
                    if (parts.length > 1) {
                        String ip = parts[1];
                        if (!ipThreatScores.containsKey(ip)) {
                            ipThreatScores.put(ip, 0);
                        }
                        updateThreatScore(ip, ipThreatScores, blacklistUrl);
                    }
                }
            } catch (IOException e) {
                System.out.println("Error reading log file: " + e.getMessage());
            }
        }
    }

    private static void updateThreatScore(String ip, Map<String, Integer> ipThreatScores, String blacklistUrl) {
        int threatScore = ipThreatScores.get(ip);
        try {
            HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(blacklistUrl + "?ip=" + ip))
                    .GET()
                    .build();
            HttpResponse<String> response = HttpClient.newHttpClient().send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() == 200) {
                int blacklistScore = Integer.parseInt(response.body());
                ipThreatScores.put(ip, threatScore + blacklistScore);
                System.out.println("Updated threat score for IP " + ip + ": " + ipThreatScores.get(ip));
            } else {
                System.out.println("Failed to retrieve blacklist data for IP " + ip);
            }
        } catch (Exception e) {
            System.out.println("Error updating threat score for IP " + ip + ": " + e.getMessage());
        }
    }
}
