use tokio::prelude::*;
use tokio::sync::Mutex;
use tokio::time::{interval, Duration};
use sha2::{Sha256, Digest};
use log::{info, error};

const LOG_FILE: &str = "log.txt";

async fn monitor_directory(path: &str) {
    let mut file_hashes = Mutex::new(hash_files(path));
    tokio::spawn(interval(Duration::from_secs(1)).select(|_| {
        let path = path.to_string();
        fs::read_dir(path).await.map_err(|e| error!("Error reading directory: {}", e))?;
        for entry in fs::read_dir(path).await {
            let entry = entry.unwrap();
            let entry_path = entry.path();
            if entry_path.is_file() {
                let mut file_hash = file_hashes.lock().unwrap();
                if let Some(hash) = file_hash.get(&entry_path) {
                    if !entry_path.to_str().unwrap().ends_with(".txt") {
                        if *hash != entry_path.to_str().unwrap().to_string() {
                            log_file(&entry_path, &hash).await;
                            *file_hash.insert(entry_path, entry_path.to_str().unwrap().to_string());
                        }
                    }
                } else {
                    log_file(&entry_path, entry_path.to_str().unwrap().to_string()).await;
                    *file_hash.insert(entry_path, entry_path.to_str().unwrap().to_string());
                }
            }
        }
    }));
}

async fn log_file(entry_path: &str, new_hash: &str) {
    let now = SystemTime::now();
    let timestamp = now.duration_since(SystemTime::UNIX_EPOCH).unwrap().as_secs();
    let contents = fs::read_to_string(entry_path).await.unwrap();
    let mut file_hash = Sha256::new();
    file_hash.update(contents.as_bytes());
    let hash = format!("{:x}", file_hash.finalize());
    let mut file = io::BufWriter::new(io::File::create(LOG_FILE).unwrap());
    writeln!(file, "{} - {} - {} - {}", timestamp, entry_path, new_hash, hash).unwrap();
}

fn hash_files(path: &str) -> HashMap<PathBuf, String> {
    let mut file_hashes = HashMap::new();
    fs::read_dir(path).unwrap().for_each(|entry| {
        let entry = entry.unwrap();
        let entry_path = entry.path();
        if entry_path.is_file() {
            let mut file_hash = Sha256::new();
            file_hash.update(fs::read(entry_path).unwrap());
            file_hashes.insert(entry_path, format!("{:x}", file_hash.finalize()));
        }
    });
    file_hashes
}

#[tokio::main]
async fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        panic!("Please provide a directory path");
    }
    let path = &args[1];
    monitor_directory(path).await;
}
