use async_std::prelude::*;
use async_std::task;
use diesel::prelude::*;
use diesel::r2d2::{ConnectionManager, Pool};
use diesel::result::Error;
use log::{info, error};
use chrono::prelude::*;

const DB_URL: &str = "postgres://user:password@localhost:5432/database";
const MIGRATION_DIR: &str = "migrations";

#[derive(Debug, Queryable)]
struct Migration {
    name: String,
    applied_at: NaiveDateTime,
}

#[derive(Debug, Insertable)]
struct NewMigration {
    name: String,
    applied_at: NaiveDateTime,
}

#[derive(Debug, Queryable, Serialize, Deserialize)]
struct Database {
    migrations: Vec<Migration>,
}

#[derive(Debug, Insertable)]
struct NewDatabase {
    migrations: Vec<Migration>,
}

#[tokio::main]
async fn main() -> Result<(), Error> {
    env_logger::init();

    let migrations = fs::read_dir(MIGRATION_DIR)
        .await
        .unwrap()
        .map(|entry| entry.unwrap().path().file_name().unwrap().to_str().unwrap())
        .collect::<Vec<_>>();

    let manager = ConnectionManager::<PgConnection>::new(DB_URL);
    let pool = Pool::new(manager).unwrap();

    let db = pool.get().await.unwrap();

    let migrations = migrations
        .into_iter()
        .map(|name| Migration {
            name: name.to_string(),
            applied_at: NaiveDateTime::from_timestamp(0, 0),
        })
        .collect::<Vec<_>>();

    diesel::insert_into(db.migrations)
        .values(&NewMigration {
            name: migrations
                .iter()
                .map(|m| m.name.clone())
                .collect::<Vec<_>>()
                .join(","),
            applied_at: NaiveDateTime::from_timestamp(0, 0),
        })
        .execute(&db)
        .await?;

    for migration in migrations {
        let conn = pool.get().await.unwrap();
        let migration = Migration {
            name: migration.name.clone(),
            applied_at: migration.applied_at,
        };

        let conn = conn.get_schema("public")?;

        let result = diesel::update(db.migrations)
            .set(db.migrations.applied_at.eq(migration.applied_at))
            .where(db.migrations.name.eq(migration.name))
            .execute(&conn)?;

        if result == 0 {
            let conn = conn.get_schema("public")?;

            diesel::insert_into(db.migrations)
                .values(&NewMigration {
                    name: migration.name.clone(),
                    applied_at: migration.applied_at,
                })
                .execute(&conn)?;
        }
    }

    info!("Migrations applied successfully");

    Ok(())
}
