import java.io.*;
import java.nio.file.*;
import java.nio.file.attribute.BasicFileAttributes;
import java.nio.file.attribute.PosixFilePermission;
import java.nio.file.attribute.PosixFilePermissions;
import java.util.ArrayList;
import java.util.List;
import java.util.logging.FileHandler;
import java.util.logging.Logger;
import java.util.logging.SimpleFormatter;
import java.util.regex.Pattern;

import org.json.JSONObject;

public class ConfigFileWatcher {
    private static final Logger logger = Logger.getLogger(ConfigFileWatcher.class.getName());
    private static final Pattern pattern = Pattern.compile("config/(\\w+\\.config)$");

    public static void main(String[] args) throws IOException {
        // Initialize logger
        logger.setLevel(Level.ALL);
        FileHandler fileHandler = new FileHandler("config_file_watcher.log", true);
        logger.addHandler(fileHandler);
        SimpleFormatter formatter = new SimpleFormatter();
        fileHandler.setFormatter(formatter);

        // Create directories to watch
        Path dirToWatch = Paths.get("config");
        try {
            Files.walkFileTree(dirToWatch, new SimpleFileVisitor<Path>() {
                @Override
                public FileVisitResult visitFile(Path file, BasicFileAttributes attrs) throws IOException {
                    if (pattern.matcher(file.getFileName().toString()).matches()) {
                        logger.info("Watching file: " + file);
                    }
                    return FileVisitResult.CONTINUE;
                }
            });
        } catch (SecurityException e) {
            System.out.println("Security Exception: " + e.getMessage());
        }

        // Watch for file modifications, creations, or deletions
        WatchService watchService = FileSystems.getDefault().newWatchService();
        try {
            dirToWatch.register(watchService, StandardWatchEventKinds.ENTRY_CREATE, StandardWatchEventKinds.ENTRY_DELETE, StandardWatchEventKinds.ENTRY Modify);

            while (true) {
                WatchKey key = watchService.take();
                for (WatchEvent<?> event : key.pollEvents()) {
                    Path file = (Path) event.context();
                    logger.info("File event: " + event.kind() + ", " + file);

                    try {
                        // Get file attributes
                        BasicFileAttributes attrs = Files.readAttributes(file, BasicFileAttributes.class);

                        // Log file details
                        String eventType = event.kind().toString();
                        logger.info("Event type: " + eventType);
                        logger.info("File name: " + file.getFileName());
                        logger.info("Timestamp: " + attrs.lastModifiedTime());
                        logger.info("File size: " + attrs.size());
                        logger.info("Permissions: " + attrs.permissions());

                        // Log to JSON file
                        JSONObject jsonObject = new JSONObject();
                        jsonObject.put("event_type", eventType);
                        jsonObject.put("file_name", file.getFileName().toString());
                        jsonObject.put("timestamp", attrs.lastModifiedTime());
                        jsonObject.put("file_size", attrs.size());
                        jsonObject.put("permissions", attrs.permissions());

                        FileWriter writer = new FileWriter("file_event.log", true);
                        writer.write(jsonObject.toString() + "\n");
                        writer.close();
                    } catch (IOException e) {
                        System.out.println("IO Exception: " + e.getMessage());
                    }
                }
                key.reset();
            }
        } finally {
            watchService.shutdown();
        }
    }
}
