import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.Scanner;
import java.util.concurrent.TimeUnit;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;

import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.List;

public class WebServerHealthMonitor {

    public static void main(String[] args) {
        // Create a configuration file path
        String configFilePath = "config.json";

        // Load the configuration from the file
        Gson gson = new GsonBuilder().setPrettyPrinting().create();
        String config = new String(Files.readAllBytes(Paths.get(configFilePath)));
        WebServerHealthMonitorConfig configData = gson.fromJson(config, WebServerHealthMonitorConfig.class);

        // Create a list of web servers
        List<String> webServers = configData.getUrls();

        // Create an executor service for asynchronous requests
        ExecutorService executor = Executors.newFixedThreadPool(webServers.size());

        // Create a client and start monitoring the web servers
        HttpClient client = HttpClient.newHttpClient();
        for (String url : webServers) {
            CompletableFuture<Void> future = CompletableFuture.runAsync(() -> {
                try {
                    // Send an HTTP GET request to the web server
                    HttpRequest request = HttpRequest.newBuilder()
                            .uri(URI.create(url))
                            .build();

                    // Get the response
                    HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());

                    // Log the response
                    System.out.println("URL: " + url);
                    System.out.println("Status: " + response.statusCode());
                    System.out.println("Body: " + response.body());
                } catch (IOException | InterruptedException e) {
                    // Log the exception
                    System.out.println("Exception occurred while monitoring " + url + ": " + e.getMessage());
                }
            }, executor);
        }

        // Shut down the executor service
        executor.shutdown();
        try {
            executor.awaitTermination(1, TimeUnit.MINUTES);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    private static class WebServerHealthMonitorConfig {
        private List<String> urls;

        public List<String> getUrls() {
            return urls;
        }
    }
}
