use std::collections::HashMap;
use std::io;
use std::net::Url;
use tokio;
use tokio::prelude::*;
use tokio::sync::mpsc;
use tokio::task;
use reqwest;
use regex::Regex;

async fn fetch_url(url: &str) -> Result<String, reqwest::Error> {
    let res = reqwest::get(url).await?;
    let html = res.text().await?;
    Ok(html)
}

async fn extract_title(html: &str) -> Result<String, regex::Error> {
    let re = Regex::new(r"<title>(.*?)</title>").unwrap();
    let cap = re.captures(html).unwrap();
    Ok(cap[1].to_string())
}

async fn process_url(url: &str) -> Result<(String, String), reqwest::Error> {
    let html = fetch_url(url).await?;
    let title = extract_title(&html).await?;
    Ok((url.to_string(), title))
}

#[tokio::main]
async fn main() {
    let (tx, rx) = mpsc::channel(100);

    for line in io::stdin().lines() {
        if let Ok(line) = line {
            let url = line.trim().to_string();
            let handle = task::spawn(async move {
                let (title, _) = process_url(&url).await.unwrap();
                tx.send((url, title)).unwrap();
            });
            handle.await.unwrap();
        }
    }

    while let Some((url, title)) = rx.recv().await {
        println!("{}: {}", url, title);
    }
}
