import json
import os
from concurrent.futures import ThreadPoolExecutor
from typing import Dict, List

def extract_comments(filename: str) -> Dict[str, List[str]]:
    """Extract comments from a Python file."""
    comments = []
    with open(filename, 'r') as file:
        for line in file:
            line = line.strip()
            if line.startswith('#'):
                comments.append(line)
    return {'filename': filename, 'comments': comments}

def main(directory: str) -> None:
    """Extract comments from multiple Python script files in a directory."""
    results: Dict[str, Dict[str, List[str]]] = {}
    with ThreadPoolExecutor() as executor:
        futures = {executor.submit(extract_comments, os.path.join(directory, filename)): filename for filename in os.listdir(directory) if filename.endswith('.py')}
        for future in futures:
            filename = futures[future]
            try:
                result = future.result()
                results[filename] = result
            except Exception as e:
                print(f"Error processing {filename}: {e}")
    with open('comments.json', 'w') as file:
        json.dump(results, file, indent=4)

if __name__ == '__main__':
    main(os.getcwd())
