use serde_json::Value;

#[tokio::main]
async fn main() {
    // Set up logging
    env_logger::init();

    // Set up TCP listener
    let listener = async_std::net::TcpListener::bind("127.0.0.1:8080").await.unwrap();
    info!("Listening on port 8080");

    loop {
        // Accept incoming connections
        let (stream, _) = listener.accept().await.unwrap();

        // Spawn new task for handling the stream
        task::spawn(handle_stream(stream).await);
    }
}

async fn handle_stream(mut stream: async_std::net::TcpStream) {
    // Read incoming JSON payload
    let mut buffer = [0; 512];
    let n = stream.read(&mut buffer).await.unwrap();
    let payload = std::str::from_utf8(&buffer[..n]).unwrap();

    // Deserialize JSON payload
    let data: Value = match serde_json::from_str(payload) {
        Ok(data) => data,
        Err(err) => {
            error!("Error deserializing JSON: {}", err);
            return;
        }
    };

    // Apply custom business logic
    let result = apply_business_logic(data);

    // Serialize result back to JSON
    let result_json = serde_json::to_value(result).unwrap();

    // Write result back to the stream
    stream.write_all(result_json.to_string().as_bytes()).await.unwrap();

    // Flush the stream
    stream.flush().await.unwrap();
}

fn apply_business_logic(data: Value) -> Value {
    // Custom business logic goes here
    // For demonstration purposes, just return the original data
    data.clone()
}
