import java.util.List;
import java.util.stream.Collectors;

import javax.persistence.EntityManager;
import javax.persistence.EntityManagerFactory;
import javax.persistence.EntityTransaction;
import javax.persistence.Persistence;
import javax.persistence.PersistenceContext;
import javax.persistence.Query;
import javax.persistence.QueryResult;
import javax.persistence.SealedSynchronizedSet;
import javax.persistence.SynchronizedSet;
import javax.persistence.Transient;
import javax.persistence.TypedQuery;
import javax.persistence.TypedQueryResult;

import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.common.serialization.StringDeserializer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Properties;

public class ECommerceService {

    private static final Logger LOGGER = LoggerFactory.getLogger(ECommerceService.class);
    private static final String KAFKA_TOPIC = "ecommerce_transactions";
    private static final String POSTGRES_URL = "jdbc:postgresql://localhost:5432/ecommerce";
    private static final String POSTGRES_USERNAME = "username";
    private static final String POSTGRES_PASSWORD = "password";

    private final ObjectMapper objectMapper;
    private final EntityManagerFactory entityManagerFactory;
    private final EntityManager entityManager;
    private final EntityTransaction transaction;

    public ECommerceService() {
        objectMapper = new ObjectMapper();
        entityManagerFactory = Persistence.createEntityManagerFactory(POSTGRES_URL);
        entityManager = entityManagerFactory.createEntityManager();
        transaction = entityManager.getTransaction();
    }

    public void processTransactions() throws Exception {
        Properties kafkaProperties = new Properties();
        kafkaProperties.put("bootstrap.servers", "localhost:9092");
        kafkaProperties.put("key.deserializer", StringDeserializer.class.getName());
        kafkaProperties.put("value.deserializer", StringDeserializer.class.getName());

        Thread kafkaThread = new Thread(() -> {
            try (org.apache.kafka.clients.consumer.KafkaConsumer<String, String> consumer = new org.apache.kafka.clients.consumer.KafkaConsumer<>(kafkaProperties)) {
                consumer.subscribe(List.of(KAFKA_TOPIC));

                while (true) {
                    ConsumerRecord<String, String> record = consumer.poll(100);
                    if (record == null) {
                        break;
                    }

                    String message = record.value();
                    JsonNode jsonNode = objectMapper.readTree(message);
                    Transaction transactionRecord = TransactionRecord.fromJson(jsonNode);

                    if (transactionRecord == null) {
                        LOGGER.error("Invalid transaction record: {}", message);
                        return;
                    }

                    transaction.begin();
                    try {
                        persistTransaction(transactionRecord);
                    } catch (Exception e) {
                        transaction.rollback();
                        LOGGER.error("Error processing transaction: {}", e.getMessage());
                    } finally {
                        transaction.commit();
                    }
                }
            }
        });
        kafkaThread.start();
    }

    @Record
    public static class TransactionRecord {
        private final String id;
        private final LocalDateTime timestamp;
        private final double amount;
        private final String paymentMethod;

        public TransactionRecord(String id, LocalDateTime timestamp, double amount, String paymentMethod) {
            this.id = id;
            this.timestamp = timestamp;
            this.amount = amount;
            this.paymentMethod = paymentMethod;
        }

        public static TransactionRecord fromJson(JsonNode jsonNode) {
            return new TransactionRecord(
                    jsonNode.get("id").asText(),
                    jsonNode.get("timestamp").asText(),
                    jsonNode.get("amount").asDouble(),
                    jsonNode.get("paymentMethod").asText()
            );
        }

        public String getId() {
            return id;
        }

        public LocalDateTime getTimestamp() {
            return LocalDateTime.parse(timestamp);
        }

        public double getAmount() {
            return amount;
        }

        public String getPaymentMethod() {
            return paymentMethod;
        }
    }

    private void persistTransaction(TransactionRecord transactionRecord) throws Exception {
        // Validate transaction data
        if (transactionRecord.getAmount() <= 0) {
            throw new IllegalArgumentException("Invalid transaction amount");
        }

        // Persist transaction data into PostgreSQL database
        TypedQuery<SealedSynchronizedSet<TransactionRecord>> query = entityManager.createQuery(
                "SELECT s FROM SealedSynchronizedSet<TransactionRecord> s WHERE s.id = :id", SealedSynchronizedSet.class
        );
        query.setParameter("id", transactionRecord.getId());
        TypedQueryResult<SealedSynchronizedSet<TransactionRecord>> result = query.getSingleResult();

        if (result != null) {
            LOGGER.error("Transaction with id {} already exists", transactionRecord.getId());
            throw new IllegalArgumentException("Duplicate transaction id");
        }

        Query<SealedSynchronizedSet<TransactionRecord>> query1 = entityManager.createQuery(
                "INSERT INTO transactions (id, timestamp, amount, paymentMethod) VALUES (:id, :timestamp, :amount, :paymentMethod)", SealedSynchronizedSet.class
        );
        query1.setParameter("id", transactionRecord.getId());
        query1.setParameter("timestamp", transactionRecord.getTimestamp());
        query1.setParameter("amount", transactionRecord.getAmount());
        query1.setParameter("paymentMethod", transactionRecord.getPaymentMethod());
        query1.executeUpdate();
    }

    public static void main(String[] args) throws Exception {
        ECommerceService service = new ECommerceService();
        service.processTransactions();
    }
