use std::env;
use std::fs;
use std::path::Path;
use tokio::prelude::*;
use tokio::task::spawn_blocking;
use tokio::time::{sleep, Duration};
use aws_s3::{Client, ClientError};
use aws_config::from_env;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Set up AWS config
    let aws_config = from_env();
    let s3 = Client::new(aws_config);

    // Monitor directory for file creation events
    let dir = env::var("INPUT_DIR")?;
    let dir_path = Path::new(&dir);
    if !dir_path.exists() {
        return Err("Directory does not exist".into());
    }

    // Spawn a new task to monitor directory for file creation events
    let mut handle = tokio::spawn(async move {
        loop {
            sleep(Duration::from_secs(1)).await;
            let files = fs::read_dir(dir_path).await?;
            for entry in files {
                let entry = entry.unwrap();
                let file_path = entry.path();
                if file_path.is_file() {
                    let file_name = file_path.file_name().unwrap().to_str().unwrap();
                    let file_path_str = file_path.to_str().unwrap();
                    println!("Uploading file: {}", file_name);
                    upload_file(s3, file_path_str).await?;
                }
            }
        }
    });

    // Wait for the handle to finish
    handle.await?;

    Ok(())
}

#[tokio::main]
async fn upload_file(s3: Client, file_path: &str) -> Result<(), Box<dyn std::error::Error>> {
    // Upload file to S3
    let bucket = env::var("S3_BUCKET")?;
    let object_key = env::var("S3_OBJECT_KEY")?;
    let params = aws_s3::PutObjectRequest {
        bucket,
        key: object_key,
        body: fs::File::open(file_path).unwrap(),
        content_type: "application/octet-stream".to_string(),
    };

    let result = s3.put_object(params).send().await?;
    if result.status().is_success() {
        println!("File uploaded successfully: {}", file_path);
    } else {
        println!("File upload failed: {}", file_path);
    }

    Ok(())
}
