import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.atomic.AtomicReference;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.util.List;
import java.util.stream.Collectors;

import java.util.concurrent.locks.Lock;
import java.util.concurrent.locks.ReentrantLock;

public class StockMarketAnalyzer {
    private static final int NUM_THREADS = Runtime.getRuntime().availableProcessors();
    private static final Lock lock = new ReentrantLock();
    private static final ConcurrentMap<String, Stock> stocks = new ConcurrentHashMap<>();
    private static final AtomicReference<AtomicLong> movingAverages = new AtomicReference<>(new AtomicLong[0]);
    private static final AtomicReference<AtomicLong> fluctuations = new AtomicReference<>(new AtomicLong[0]);

    public static void main(String[] args) throws IOException, InterruptedException {
        ExecutorService executor = Executors.newWorkStealingPool(NUM_THREADS);

        while (true) {
            String stockSymbol = simulateStreamingApi();
            processStockData(stockSymbol, executor);
        }
    }

    private static String simulateStreamingApi() {
        // Simulate a streaming API
        String[] stockSymbols = {"AAPL", "GOOG", "MSFT"};
        return stockSymbols[new java.util.Random().nextInt(stockSymbols.length)];
    }

    private static void processStockData(String stockSymbol, ExecutorService executor) throws IOException, InterruptedException {
        Stock stock = getOrCreateStock(stockSymbol);
        lock.lock();
        try {
            updateMovingAverages(stock);
            updateFluctuations(stock);
        } finally {
            lock.unlock();
        }

        // Consume data from the simulated streaming API and calculate moving averages and fluctuations
        calculateMovingAverages(stock);
        calculateFluctuations(stock);

        // Expose key metrics and alerts via a RESTful API
        exposeMetrics(stock);
    }

    private static void updateMovingAverages(Stock stock) {
        movingAverages.get().push(stock.getAverage());
    }

    private static void updateFluctuations(Stock stock) {
        fluctuations.get().push(stock.getFluctuation());
    }

    private static void calculateMovingAverages(Stock stock) {
        // Calculate moving averages for the selected stocks
        List<Double> movingAveragesList = movingAverages.get().stream()
                .mapToDouble(average -> average.getAverage())
                .collect(Collectors.toList());
        movingAverages.set(new AtomicLong[]{movingAveragesList.get(0), movingAveragesList.get(1)});
    }

    private static void calculateFluctuations(Stock stock) {
        // Calculate fluctuations for the selected stocks
        List<Double> fluctuationsList = fluctuations.get().stream()
                .mapToDouble(fluctuation -> fluctuation.getFluctuation())
                .collect(Collectors.toList());
        fluctuations.set(new AtomicLong[]{fluctuationsList.get(0), fluctuationsList.get(1)});
    }

    private static void exposeMetrics(Stock stock) throws IOException, InterruptedException {
        HttpClient client = HttpClient.newHttpClient();
        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create("http://localhost:8080/metrics"))
                .header("Content-Type", "application/json")
                .build();

        HttpResponse<JsonNode> response = client.send(request, Duration.ofSeconds(10));

        if (response.statusCode() == 200) {
            ObjectMapper mapper = new ObjectMapper();
            JsonNode metricsNode = mapper.readTree(response.body());
            ObjectNode metrics = (ObjectNode) metricsNode.get("metrics");

            ArrayNode stocksNode = (ArrayNode) metrics.get("stocks");
            stocksNode.add(new ObjectMapper().valueToTree(stock.toMap()).toString());
        }
    }

    private static Stock getOrCreateStock(String stockSymbol) {
        lock.lock();
        try {
            if (!stocks.containsKey(stockSymbol)) {
                stocks.put(stockSymbol, new Stock(stockSymbol));
            }
            return stocks.get(stockSymbol);
        } finally {
            lock.unlock();
        }
    }

    private static class Stock {
        private final String symbol;
        private double average;
        private double fluctuation;

        public Stock(String symbol) {
            this.symbol = symbol;
            this.average = 0;
            this.fluctuation = 0;
        }

        public String getSymbol() {
            return symbol;
        }

        public double getAverage() {
            return average;
        }

        public void setAverage(double average) {
            this.average = average;
        }

        public double getFluctuation() {
            return fluctuation;
        }

        public void setFluctuation(double fluctuation) {
            this.fluctuation = fluctuation;
        }

        public JsonNode toMap() {
            ObjectMapper mapper = new ObjectMapper();
            ObjectNode stockNode = mapper.createObjectNode();
            stockNode.put("symbol", symbol);
            stockNode.put("average", average);
            stockNode.put("fluctuation", fluctuation);
            return stockNode;
        }
    }
}
