use std::fs::File;
use std::io::{BufReader, BufWriter};
use std::path::Path;
use std::thread;
use std::time::Duration;

use async_trait::async_trait;
use image::{DynamicImage, GenericImageView, ImageBuffer, Luma, RgbaImage};
use image::filter::FilterType;
use tokio;
use tokio::prelude::*;
use tokio::sync::mpsc;
use tokio::task;

mod image_migrator {
    use super::*;

    #[async_trait]
    pub trait ImageMigrator {
        async fn migrate(&self, src_dir: &str, dst_dir: &str, resolution: (u32, u32));
    }

    pub struct ImageMigratorImpl {
        src_dir: String,
        dst_dir: String,
        resolution: (u32, u32),
    }

    impl ImageMigratorImpl {
        pub fn new(src_dir: &str, dst_dir: &str, resolution: (u32, u32)) -> Self {
            Self {
                src_dir: src_dir.to_string(),
                dst_dir: dst_dir.to_string(),
                resolution,
            }
        }
    }

    #[async_trait]
    impl ImageMigrator for ImageMigratorImpl {
        async fn migrate(&self, src_dir: &str, dst_dir: &str, resolution: (u32, u32)) {
            let (tx, rx) = mpsc::channel(10);
            let src_dir = Path::new(&self.src_dir);
            let dst_dir = Path::new(&self.dst_dir);

            let mut workers = vec![];

            for entry in src_dir.read_dir().unwrap() {
                let entry = entry.unwrap();
                let path = entry.path();
                if path.is_file() && path.extension().unwrap().to_str().unwrap() == "jpg" || path.extension().unwrap().to_str().unwrap() == "png" {
                    let src_path = path;
                    let dst_path = dst_dir.join(path.file_name().unwrap().to_str().unwrap());

                    let task = async move {
                        let src_img = image::open(src_path).unwrap();
                        let resized_img = resize_image(src_img, resolution.0, resolution.1);
                        let (tx, rx) = mpsc::channel(1);
                        let _ = tx.send(resized_img);
                        let _ = rx.recv();
                    };

                    workers.push(task);

                    let tx = tx;
                    let rx = rx;
                    let worker = task.await;
                    workers.push(worker);
                }
            }

            for worker in workers {
                worker.await.unwrap();
            }
        }
    }

    fn resize_image(img: DynamicImage, new_width: u32, new_height: u32) -> RgbaImage {
        let (width, height) = img.dimensions();
        let aspect_ratio = width as f64 / height as f64;

        if width > height {
            let new_width = width * (new_height as f64 / new_width as f64);
            let new_height = new_height;
            let mut img = img.resize((new_width as u32, new_height as u32), FilterType::Nearest);
            img = img.resize((new_width as u32, new_height as u32), FilterType::Lanczos3);
            img = img.resize((new_width as u32, new_height as u32), FilterType::Lanczos5);
            img = img.resize((new_width as u32, new_height as u32), FilterType::Bicubic);
            img = img.resize((new_width as u32, new_height as u32), FilterType::Bilinear);
        } else {
            let new_width = width;
            let new_height = height * (new_width as f64 / new_width as f64);
            let mut img = img.resize((new_width as u32, new_height as u32), FilterType::Nearest);
            img = img.resize((new_width as u32, new_height as u32), FilterType::Lanczos3);
            img = img.resize((new_width as u32, new_height as u32), FilterType::Lanczos5);
            img = img.resize((new_width as u32, new_height as u32), FilterType::Bicubic);
            img = img.resize((new_width as u32, new_height as u32), FilterType::Bilinear);
        }

        img
    }
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() != 4 {
        println!("Usage: {} <src_dir> <dst_dir> <resolution>", args[0]);
        return;
    }

    let src_dir = &args[1];
    let dst_dir = &args[2];
    let resolution: (u32, u32) = {
        let mut parts = args[3].split(',');
        let width: u32 = parts.next().unwrap().parse().unwrap();
        let height: u32 = parts.next().unwrap().parse().unwrap();
        (width, height)
    };

    let migrator = image_migrator::ImageMigratorImpl::new(src_dir, dst_dir, resolution);
    migrator.migrate(src_dir, dst_dir, resolution).await.unwrap();
}
