use std::env;
use std::fs::File;
use std::io::{BufReader, BufWriter, Read, Write};
use std::path::Path;
use std::sync::Arc;
use std::thread;
use std::thread::JoinHandle;
use std::time::Duration;

use gzip::Writer as GzipWriter;

fn main() {
    let filenames = get_filenames_from_stdin();

    let num_threads = 4;
    let handles: Vec<JoinHandle<()>> = filenames
        .into_iter()
        .map(|filename| {
            let filename = filename.clone();
            thread::spawn(move || {
                compress_file(filename);
            })
        })
        .collect();

    for handle in handles {
        handle.join().unwrap();
    }
}

fn get_filenames_from_stdin() -> Vec<String> {
    let stdin = env::stdin();
    let mut buffer = String::new();
    stdin.read_line(&mut buffer).unwrap();
    let filenames = buffer.trim().split_whitespace().map(|s| s.to_string()).collect();
    filenames
}

fn compress_file(filename: String) {
    let filepath = Path::new(&filename);
    let file_path = filepath.with_extension("");
    let file = match File::open(file_path) {
        Ok(file) => file,
        Err(e) => {
            eprintln!("Error opening file: {}", e);
            return;
        }
    };

    let (reader, writer) = std::io::pipe();
    let reader = BufReader::new(reader);
    let writer = BufWriter::new(writer);

    match file.read_to_end(&mut reader) {
        Ok(_) => {
            let mut writer = GzipWriter::new(writer);
            writer.write_all(&reader.bytes().collect::<Vec<_>>()).unwrap();
            writer.finish().unwrap();
        }
        Err(e) => {
            eprintln!("Error reading file: {}", e);
        }
    }

    match writer.flush() {
        Ok(_) => println!("Compressed file: {}", file_path.with_extension("gz")),
        Err(e) => {
            eprintln!("Error flushing writer: {}", e);
        }
    }
}
